namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- CalculateTotal: DataRow for inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result, $"Expected {expected} but got {result}");
    }

    // --- CalculateTotal: DynamicData for complex/edge cases ---

    [TestMethod]
    [DynamicData(nameof(InvalidCalculateTotalInputs), DynamicDataSourceType.Method)]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParamName)
    {
        var ex = Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName);
    }

    private static IEnumerable<object[]> InvalidCalculateTotalInputs()
    {
        yield return new object[] { -1m, 1, 0.1m, "unitPrice" };
        yield return new object[] { 10m, -1, 0.1m, "quantity" };
        yield return new object[] { 10m, 1, -0.01m, "taxRate" };
        yield return new object[] { 10m, 1, 1.01m, "taxRate" };
    }

    // --- ApplyDiscount: DataRow for inline cases ---

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData with property source ---

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountInputs))]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));
    }

    public static IEnumerable<object[]> InvalidDiscountInputs => new[]
    {
        new object[] { 100m, -1m },
        new object[] { 100m, 101m },
        new object[] { 50m, -0.01m },
        new object[] { 50m, 100.01m },
    };
}

